import { GetRecoveryMethodsUseCase } from '../../../src/application/use-cases/GetRecoveryMethodsUseCase';
import { IRecoveryMethodRepository } from '../../../src/domain/repositories/IRecoveryMethodRepository';
import { ICircuitBreaker } from '../../../src/application/services/ICircuitBreaker';
import { ILogger } from '@shared/application/services/logger.interface';
import { RecoveryMethod } from '../../../src/domain/value-objects/RecoveryMethod';

// Mock logger
const mockLogger: ILogger = {
  info: jest.fn(),
  error: jest.fn(),
  warn: jest.fn(),
  debug: jest.fn(),
  fatal: jest.fn(),
};

// Mock circuit breaker
const mockCircuitBreaker: ICircuitBreaker = {
  execute: jest.fn(async (fn) => await fn()),
  getState: jest.fn().mockReturnValue('CLOSED'),
  reset: jest.fn(),
};

// Mock repository
class MockRecoveryMethodRepository implements IRecoveryMethodRepository {
  private recoveryMethods: Map<string, RecoveryMethod> = new Map();

  async getByUserId(userId: string): Promise<RecoveryMethod | null> {
    return this.recoveryMethods.get(userId) || null;
  }

  async save(recoveryMethod: RecoveryMethod): Promise<RecoveryMethod> {
    this.recoveryMethods.set(recoveryMethod.userId, recoveryMethod);
    return recoveryMethod;
  }

  async delete(userId: string): Promise<void> {
    this.recoveryMethods.delete(userId);
  }

  async isRecoveryEmailUsed(email: string, excludeUserId?: string): Promise<boolean> {
    for (const [userId, method] of this.recoveryMethods.entries()) {
      if (userId !== excludeUserId && method.toObject().recoveryEmail === email) {
        return true;
      }
    }
    return false;
  }

  async findUserIdByRecoveryEmail(email: string): Promise<string | null> {
    for (const [userId, method] of this.recoveryMethods.entries()) {
      if (method.toObject().recoveryEmail === email) {
        return userId;
      }
    }
    return null;
  }

  // Helper methods for testing
  addRecoveryMethod(recoveryMethod: RecoveryMethod): void {
    this.recoveryMethods.set(recoveryMethod.userId, recoveryMethod);
  }

  clear(): void {
    this.recoveryMethods.clear();
  }
}

describe('GetRecoveryMethodsUseCase', () => {
  let useCase: GetRecoveryMethodsUseCase;
  let mockRepository: MockRecoveryMethodRepository;
  const testUserId = 'user-123';

  beforeEach(() => {
    mockRepository = new MockRecoveryMethodRepository();
    jest.clearAllMocks();
    useCase = new GetRecoveryMethodsUseCase(
      mockRepository,
      mockLogger,
      mockCircuitBreaker
    );
  });

  describe('execute', () => {
    it('should get recovery methods successfully', async () => {
      // Arrange
      const recoveryMethod = RecoveryMethod.create({
        userId: testUserId,
        recoveryEmail: 'recovery@example.com',
        recoveryEmailVerified: true,
        recoveryEmailVerifiedAt: new Date(),
        createdAt: new Date(),
        lastUpdatedAt: new Date()
      });
      mockRepository.addRecoveryMethod(recoveryMethod);

      // Act
      const result = await useCase.execute({ userId: testUserId });

      // Assert
      expect(result.success).toBe(true);
      expect(result.recoveryMethods).toBeDefined();
      expect(result.recoveryMethods?.recoveryEmail).toBe('recovery@example.com');
      expect(result.recoveryMethods?.recoveryEmailVerified).toBe(true);
    });

    it('should return default when no recovery methods configured', async () => {
      // Act
      const result = await useCase.execute({ userId: testUserId });

      // Assert
      expect(result.success).toBe(true);
      expect(result.recoveryMethods).toBeDefined();
      expect(result.recoveryMethods?.recoveryEmail).toBeNull();
      expect(result.recoveryMethods?.recoveryEmailVerified).toBe(false);
    });

    it('should return error when userId is empty', async () => {
      // Act
      const result = await useCase.execute({ userId: '' });

      // Assert
      expect(result.success).toBe(false);
      expect(result.error).toBe('INVALID_USER_ID');
      expect(result.message).toContain('không hợp lệ');
    });

    it('should handle repository errors gracefully', async () => {
      // Arrange
      jest.spyOn(mockRepository, 'getByUserId').mockRejectedValue(new Error('Database error'));

      // Act
      const result = await useCase.execute({ userId: testUserId });

      // Assert
      expect(result.success).toBe(false);
      expect(result.error).toBe('GET_RECOVERY_METHODS_FAILED');
      expect(mockLogger.error).toHaveBeenCalled();
    });

    it('should handle circuit breaker open state', async () => {
      // Arrange
      (mockCircuitBreaker.execute as jest.Mock).mockImplementation(async (_fn, fallback) => {
        return await fallback();
      });

      // Act
      const result = await useCase.execute({ userId: testUserId });

      // Assert
      expect(result.success).toBe(false);
      expect(result.error).toBe('SERVICE_UNAVAILABLE');
    });

    it('should log info when recovery methods retrieved', async () => {
      // Arrange
      const recoveryMethod = RecoveryMethod.create({
        userId: testUserId,
        recoveryEmail: 'recovery@example.com',
        recoveryEmailVerified: false,
        recoveryEmailVerifiedAt: null,
        createdAt: new Date(),
        lastUpdatedAt: new Date()
      });
      mockRepository.addRecoveryMethod(recoveryMethod);

      // Act
      await useCase.execute({ userId: testUserId });

      // Assert
      expect(mockLogger.info).toHaveBeenCalledWith(
        'Getting recovery methods',
        expect.objectContaining({ userId: testUserId })
      );
      expect(mockLogger.info).toHaveBeenCalledWith(
        'Recovery methods retrieved successfully',
        expect.any(Object)
      );
    });
  });
});

